-- ============================================================
-- 软件工程专业 (12个作品: Se/001-012.mp4)
-- ============================================================
INSERT INTO works (id, title, major_code, major_name, theme, tags, authors, teacher, poster_url, video_url, duration, introduction) VALUES
('w001', '基于LangChain4J的AI网站生成平台', 'software', '软件工程', '数智焕新', '["人工智能", "Web应用", "LangChain"]', '["龙文星"]', '王俊杰', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/001.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/001.mp4', '03:00', '本平台是一款面向非技术用户的智能网站生成工具，基于 LangChain4j 框架构建，通过自然语言交互即可自动完成网站结构分析、页面生成、功能配置与云端部署。支持个人展示型网站、轻量级工具应用及创意原型的快速构建，实现"需求即实现"的智能开发流程。创新亮点包括：智能路由技术自动匹配最优生成模式、Vue增量修改避免全量重写、版本隔离机制确保可追溯可回滚、全链路工程化生成流程。'),

('w002', '基于YOLO与大数据技术的交通流量智能分析系统', 'software', '软件工程', '数智焕新', '["计算机视觉", "大数据", "YOLO"]', '["陈曾烨"]', '孙佩娟', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/002.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/002.mp4', '03:00', '本作品是基于YOLO11与大数据技术的交通流量智能分析系统，面向中小规模交通场景，实现行人与车辆的自动检测、计数、数据存储及可视化分析。系统以深度学习目标检测为核心，结合视频图像处理、目标追踪与数据统计技术，可对图片、视频及摄像头实时流进行处理，完成交通流量的自动化监测。系统界面简洁易用、部署轻量化，具有较强的实用性与应用价值。'),

('w003', '基于Vue+Node.js的糖尿病健康咨询系统', 'software', '软件工程', '数智焕新', '["Web应用", "医疗健康", "Vue.js"]', '["马小念"]', '罗灿峰', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/003.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/003.mp4', '03:00', '本系统是基于Vue 3和Node.js前后端分离架构开发的糖尿病健康咨询平台。采用Element Plus组件库构建响应式界面，Express提供RESTful API，MySQL数据持久化，集成火山引擎DeepSeek大模型实现AI智能咨询，通过JWT认证保障数据安全，为糖尿病患者提供记录、分析、咨询的一站式健康管理服务。创新性地集成DeepSeek大语言模型，设计"档案-数据-语境"三重上下文注入机制，AI结合用户健康数据生成个性化建议。'),

('w004', '基于机器学习+Spark的农作物产量分析系统', 'software', '软件工程', '数智焕新', '["机器学习", "大数据", "Spark"]', '["何思瑶"]', '张明', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/004.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/004.mp4', '03:00', '本系统面向现代农业数字化、智能化需求，以Hadoop+Spark为大数据底层，采用Django、Vue、Echarts、MySQL构建Web平台。基于百万级农业数据，融合LightGBM、K-Means、FP-Growth算法，实现数据处理、多维分析、产量预测、高产规律挖掘与风险预警。系统可为农业管理人员、技术人员提供轻量化可视化服务，清晰展示气候、土壤等因素对产量的影响，为科学种植、农业规划与风险防控提供数据支撑。'),

('w005', '基于AI智能生成的视觉美化低代码UI生成器', 'software', '软件工程', '数智焕新', '["人工智能", "低代码", "UI设计"]', '["戴荃宇"]', '胡明星', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/005.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/005.mp4', '03:00', '针对传统平台视觉单一、细节难调的痛点，系统以DeepSeek大语言模型为中枢，通过自然语言描述驱动界面设计。实现从语义理解、布局生成到标准化代码导出的全流程自动化。系统核心功能包括：用户认证与项目管理、可视化编辑器、AI智能设计器（支持自然语言对话、流式响应生成界面布局）、一键导出多种格式文件。将大语言模型作为设计中枢，重构低代码交互范式。'),

('w006', '基于SpringBoot的社区活动室预约系统', 'software', '软件工程', '数智焕新', '["SpringBoot", "预约系统", "Vue"]', '["胡聪"]', '冯晓磊', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/006.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/006.mp4', '03:00', '本作品为社区活动室预约管理系统，面向居民与社区管理员提供"线上预约—线下核销—信用治理—审计追溯"的闭环服务。系统采用前后端分离架构：前端基于Vue3与Element Plus构建单页应用，后端基于Spring Boot、MyBatis-Plus与MySQL实现业务与数据管理，并集成ZXing生成核销二维码、ECharts展示管理统计。创新将"预约管理"与"信用治理"深度绑定，引入"二维码核销+随机码校验"机制。'),

('w007', '基于微信小程序+Node.js的医疗陪诊服务系统', 'software', '软件工程', '数智焕新', '["微信小程序", "Node.js", "医疗"]', '["陈瑞"]', '郭学芹', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/007.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/007.mp4', '03:00', '本毕业设计基于微信小程序、Node.js和MySQL等技术，构建了一个数字化医疗陪诊服务系统。系统采用前后端分离的架构：前端使用Uni-app框架开发微信小程序，后端采用Node.js平台的Express框架搭建RESTful API服务。系统包括用户、陪诊人员、管理后台三大模块。用户可注册登录、预约服务、管理订单、在线咨询；陪诊人员可发布服务、审核订单、统计收入；管理员可进行用户管理、数据统计、系统配置。'),

('w008', '基于SpringBoot+Vue的心理咨询系统', 'software', '软件工程', '数智焕新', '["SpringBoot", "Vue", "心理健康"]', '["罗量"]', '刘芳', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/008.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/008.mp4', '03:00', '本系统是面向高校学生的心理健康服务平台，采用SpringBoot+Vue前后端分离架构，结合MySQL、Redis实现数据存储与缓存加速。系统集成了标准化心理测评、AI智能分析、师生实时咨询三大核心模块，为学生提供便捷的心理状态筛查与个性化建议，助力高校构建高效、可落地的心理健康服务体系。创新引入AI大语言模型实现测评结果的智能解读与个性化建议生成，采用WebSocket实现实时咨询。'),

('w009', '基于语音识别的智能笔记系统', 'software', '软件工程', '数智焕新', '["语音识别", "笔记管理", "AI"]', '["刘芸"]', '夏杰', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/009.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/009.mp4', '03:00', '本作品是一款面向学习与办公场景的智能笔记管理系统，采用前后端分离架构开发，前端以Vue.js为核心构建响应式交互界面，后端基于Flask框架搭建轻量服务，搭配SQLite数据库实现数据持久化。系统集成语音实时转写、关键词智能标记、AI思维导图生成、笔记全生命周期管理、多格式导出分享五大核心功能，可将语音快速转为可编辑笔记，自动高亮关键信息，一键生成结构化思维导图。'),

('w010', '基于MCP协议的个人出行智能体', 'software', '软件工程', '数智焕新', '["MCP协议", "智能体", "出行"]', '["李荫渠"]', '林久麟', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/010.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/010.mp4', '03:00', '本作品针对出行应用数据孤岛、交互差等痛点问题，设计实现了轻量本地化智能出行助手。系统采用B/S四层架构，前端以HTML/CSS/JS构建对话界面，后端基于Node.js+Express实现网关与服务，通过Ollama本地化部署qwen3:8b模型。依托MCP协议实现工具智能调度，避免了对云端服务的依赖，在无需网络的地方也能提供出行服务。核心创新是"工具嗅探"机制，实现两层意图检测逻辑。'),

('w011', '基于RAG和DeepSeek的电脑硬件推荐系统', 'software', '软件工程', '数智焕新', '["RAG", "DeepSeek", "硬件推荐"]', '["石亿"]', '陈浩', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/011.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/011.mp4', '03:00', '本系统面向DIY装机用户痛点，依托RAG检索增强生成与DeepSeek大语言模型，打造一站式智能电脑硬件推荐平台。系统采用Spring Boot+Vue3前后端分离架构，集硬件数据爬虫、知识库管理、AI智能推荐、配置方案分享、社区交流于一体，可根据用户预算、用途自动生成兼容、高性价比装机方案。支持自然语言输入预算、用途，RAG+DeepSeek自动生成多套兼容配置。'),

('w012', '基于微信小程序的校友服务平台', 'software', '软件工程', '数智焕新', '["微信小程序", "校友服务", "社交"]', '["舒焱"]', '祝念', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/012.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Se/012.mp4', '03:00', '本作品是一个面向高校校友的综合服务平台，包含微信小程序端和Web管理后台。系统以微信小程序为载体，为校友提供一键登录、身份认证、动态社交、活动报名、返校预约、私信联络等功能；Web管理后台为学校管理员提供用户管理、内容审核、预约审批、数据统计等能力。系统旨在解决校友身份认证难、信息沟通不畅、活动组织繁琐等问题，通过数字化手段构建校友与母校之间的长效联络机制。');

-- ============================================================
-- 电子信息工程专业 (11个作品: Ele/001-011.mp4)
-- ============================================================
INSERT INTO works (id, title, major_code, major_name, theme, tags, authors, teacher, poster_url, video_url, duration, introduction) VALUES
('w013', '基于图像处理的智能车双车跟随控制研究', 'electronic', '电子信息工程', '芯火智造', '["图像处理", "智能车", "跟随控制"]', '["祝加辉"]', '蒋汪萍', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/001.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/001.mp4', '03:00', '本作品设计并实现了一套基于图像处理的智能车双车跟随控制系统，以英飞凌TC264为主控芯片，融合视觉感知、多传感器融合与串并级PID控制技术，实现前车自主循迹、后车精准跟随的协同运行。硬件上，前车采用全局快门摄像头、姿态传感器与红外发射模块；后车通过红外镜头与偏振片抗干扰定位。系统经实测，道路识别准确率超90%，双车轨迹跟随偏差≤5cm，在复杂光照下仍稳定可靠。'),

('w014', '智能快递柜控制系统的设计', 'electronic', '电子信息工程', '芯火智造', '["STM32", "RFID", "智能快递"]', '["付智宇"]', '杨洁', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/002.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/002.mp4', '03:00', '本设计针对快递服务最后一公里配送效率和安全性问题，基于STM32制作的智能快递柜控制系统。通过矩阵键盘、RFID读卡器、LCD显示屏、继电器模块、蜂鸣器以及4G通信模块等硬件，构建了一套完整的自助存取件控制系统。系统核心包括以STM32为核心的主控模块、RFID读卡模块实现对快递员身份卡检测、4G通信模块实现向用户发送短信取件码、继电器模块驱动模拟柜门开关。适用于居民住宅区、高校、写字楼等需提供24小时快递服务的区域。'),

('w015', '太阳能板自动追光系统设计', 'electronic', '电子信息工程', '芯火智造', '["太阳能", "自动追光", "STM32"]', '["龚力"]', '陶慧芳', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/003.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/003.mp4', '03:00', '本设计针对固定式太阳能光伏系统能量捕获效率低的问题，基于STM32打造双轴自动追光系统。通过光敏电阻阵列采集光照信号，驱动双轴机构精准追踪太阳方位，兼具自动/手动控制、自供电与实时显示功能，可有效提升太阳能利用率。系统采用光敏电阻阵列采集光强信号判断太阳方位，双轴执行模块实现水平旋转与俯仰角度调节，太阳能供电与锂电池充放电管理保障系统稳定运行。适用于户外监控、气象站、家用小型光伏设备等场景。'),

('w016', '遥控旋转LED显示屏的设计', 'electronic', '电子信息工程', '芯火智造', '["LED显示", "遥控", "单片机"]', '["金鹏"]', '蒋汪萍', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/004.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/004.mp4', '03:00', '本设计基于STC单片机与视觉暂留原理，实现一款遥控旋转LED显示屏。系统由直流减速电机带动LED显示板高速旋转，主控精准控制点阵亮灭时间，在人眼中形成稳定的文字/图案；同时集成红外遥控模块，可远程切换显示内容、调节亮度与模式。整体结构紧凑、效果直观，适用于桌面装饰、小型信息展示与电子教学实训。'),

('w017', '智能桌面宠物机器人设计', 'electronic', '电子信息工程', '芯火智造', '["机器人", "STM32", "语音识别"]', '["熊欣悦"]', '李文', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/005.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/005.mp4', '03:00', '本设计旨在开发一款基于STM32的智能桌面宠物机器人系统，通过集成语音识别、触摸传感、微型舵机、OLED显示屏及RGB灯带等多类交互模块，构建一套可离线运行、支持多种交互模式的情感化伴侣设备。系统可实现语音指令响应、触摸状态切换、拟人化表情与动作协同输出等基础功能，在办公、学习及居家场景中为用户提供灵活、低侵入的情感互动体验。适用于日常陪伴娱乐、氛围装饰摆件等场景。'),

('w018', '办公室智能节能照明系统的设计与实现', 'electronic', '电子信息工程', '芯火智造', '["智能照明", "节能", "STM32"]', '["艾勃霖"]', '杨洁', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/006.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/006.mp4', '03:00', '本设计针对传统办公室照明能源浪费、控制僵化的问题，基于STM32打造智能节能照明系统。通过光敏传感器与人体红外传感器采集环境光强与人员活动信息，实现人来灯亮、人走灯灭、自然光自适应调节，兼具蓝牙远程控制、实时状态显示功能，可大幅降低办公照明能耗。环境感知模块采用H1750光敏传感器+HC-SR501人体红外传感器，支持蓝牙4.0 BLE手机APP远程控制。适用于办公室、会议室、智慧楼宇等场景。'),

('w019', '基于STM32的多功能手表的设计与实现', 'electronic', '电子信息工程', '芯火智造', '["智能手表", "STM32", "可穿戴"]', '["许元基"]', '杨瑞', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/007.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/007.mp4', '03:00', '本设计基于STM32F103C8T6微控制器设计并实现一款多功能智能手表。系统集成高精度实时时钟、姿态检测、环境监测、人机交互及娱乐扩展功能，具备抬手亮屏、闹钟提醒、温湿度、气压、音乐播放、小游戏、照明等实用能力。采用DS3231高精度RTC芯片保证计时精准，MPU6050六轴传感器实现姿态检测与抬手亮屏，BME280实现温湿度和气压监测。具有低成本、低功耗、可定制、稳定可靠等特点。'),

('w020', '基于MSPM0的智能小车巡线系统的设计与实现', 'electronic', '电子信息工程', '芯火智造', '["智能小车", "巡线", "PID控制"]', '["刘润豪"]', '陶慧芳', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/008.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/008.mp4', '03:00', '设计以TI MSPM0G3507单片机为核心，构建了包含传感器、电机驱动、显示及主控模块的自动巡线小车系统。小车通过多路灰度传感器实时采集路径信息，结合编码器速度反馈，采用PID控制算法和TB6612驱动调节双电机PWM占空比，实现稳定精准循迹；同时集成MPU6050进行姿态显示，OLED实时显示运动信息。该系统具有推动物流、制造等行业从"人工操作"向"自动化作业"转型的特点。'),

('w021', '基于人脸识别的智能门禁系统设计', 'electronic', '电子信息工程', '芯火智造', '["人脸识别", "门禁", "STM32"]', '["周宝玉"]', '褚立岑', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/009.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/009.mp4', '03:00', '本设计针对传统门禁易丢失、易冒用、安全性低、管理成本高等痛点，基于STM32打造多模式智能门禁系统。融合人脸识别与射频卡双重认证，具备图像采集、身份比对、门锁控制、实时显示、远程监控与异常记录功能。以STM32F103C8T6为核心，ESP32-CAM采集人脸图像，K210实现人脸识别，RC522完成射频卡读取，ESP8266实现WiFi联网远程监控。可定制化适配企业、小区、实验室等高安全场景。'),

('w022', '基于视觉伺服的嵌入式识别与抓取系统设计', 'electronic', '电子信息工程', '芯火智造', '["视觉伺服", "机械臂", "YOLO"]', '["胡彬彬"]', '陶慧芳', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/010.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/010.mp4', '03:00', '本设计提出一种基于树莓派与STM32双主控架构的视觉伺服嵌入式目标识别与抓取系统。以树莓派作为视觉处理单元，结合摄像头模块与YOLOv8-nano深度学习目标检测模型，实现对目标的实时识别与信息获取；以STM32作为运动控制单元，通过串口通信接收目标位置信息，完成多舵机控制，驱动机械臂执行抓取动作。适用于服务机器人、智能垃圾分类、工业自动化分拣、智能仓储搬运等场景。'),

('w023', '基于STM32的气象数据采集与无线传输系统设计', 'electronic', '电子信息工程', '芯火智造', '["气象监测", "STM32", "无线传输"]', '["黄友成"]', '杨瑞', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/011.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Ele/011.mp4', '03:00', '本设计基于STM32F103C8T6单片机打造，针对传统环境监测设备功能单一、传输不便的痛点，构建了一套集成多环境参数采集、本地显示与远程传输的智能监测平台。搭载温湿度、气压、粉尘、光照、雨水、风速风向等传感器，实现环境多维数据的实时采集。集成ESP8266 WiFi模块与TTL转485模块，支持无线物联网远程传输。配套APP实时显示，支持客户端调整采集数据参数。适用于智能家居、农业大棚、户外环境监测等场景。');

-- ============================================================
-- 广播电视工程专业 (10个作品: Rte/001-010.mp4)
-- ============================================================
INSERT INTO works (id, title, major_code, major_name, theme, tags, authors, teacher, poster_url, video_url, duration, introduction) VALUES
('w024', '基于UE5的晚会虚拟植入包装系统', 'broadcast', '广播电视工程', '虚实共生', '["UE5", "虚拟演播", "实时渲染"]', '["陈亚萍"]', '张伟', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/001.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/001.mp4', '03:00', '本作品基于UE5引擎搭建晚会虚拟植入包装系统，通过集成Nanite、Lumen、Niagara等前沿技术，实现虚拟场景、道具、特效与实景舞台的高保真实时融合。系统采用模块化设计理念，核心模块涵盖舞台灯光、全息特效、动态灯牌、虚拟角色、视频播放及实时控制六大功能单元，支持4K直播渲染输出与多镜头同步控制，具备低延迟（<50ms）与亚像素级融合精度。可广泛应用于春晚、商业晚会、企业年会等演出场景。'),

('w025', '基于Python和Unity的智能虚拟演播室系统', 'broadcast', '广播电视工程', '虚实共生', '["Python", "Unity", "虚拟演播"]', '["倪灿"]', '李华', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/002.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/002.mp4', '03:00', '毕设题目是基于Python和Unity的智能虚拟演播室系统设计与实现。针对传统虚拟演播室系统在软硬件兼容、实时数据融合与流程自动化方面的不足，本系统采用分层模块化架构，由硬件采集层、Python信号处理层、通信层、Unity渲染层和输出控制层组成。核心功能包括人物抠像、多机位自动切换、语音转文字，为中小型广电机构提供了一套低成本、高灵活性的智能虚拟演播室解决方案。'),

('w026', '基于STM32的离线语音电视遥控系统', 'broadcast', '广播电视工程', '虚实共生', '["STM32", "语音识别", "遥控"]', '["刘雅丽"]', '王强', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/003.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/003.mp4', '03:00', '本作品是基于STM32的离线语音电视遥控系统，以STM32F103C8T6为控制核心，采用LD3320语音识别模块，配合红外收发与OLED显示，实现电视语音开关机、音量调节、频道切换等功能。系统无需联网即可稳定运行，具备响应快、操作简单、隐私安全等特点。有效解决传统遥控器使用繁琐、易丢失、老人小孩操作困难等问题，大幅提升电视操控的便捷性与智能化水平。'),

('w027', '基于深度学习的广电图像智能修复系统', 'broadcast', '广播电视工程', '虚实共生', '["深度学习", "图像修复", "广电"]', '["庹雨姗"]', '赵鑫', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/004.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/004.mp4', '03:00', '针对广电图像采集传输中常见的复合退化问题，本系统构建了基于深度学习的"共享主干-任务分支"多任务网络框架。通过端到端学习，系统统一提取底层特征并协同优化任务，解决了传统串行处理的误差累积，提供完整的智能化修复工具链。核心功能包括：基于CBAM的智能去噪、集成轻量级光流估计的视频去模糊、多尺度超分辨率重建、引入cGAN的自适应色彩校正。'),

('w028', '基于Unity3D的虚拟演播室背景合成系统', 'broadcast', '广播电视工程', '虚实共生', '["Unity3D", "虚拟演播", "背景合成"]', '["廖心怡"]', '黄金仙', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/005.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/005.mp4', '03:00', '针对传统实体演播室建设成本高、场景切换困难、对专业硬件依赖强等问题，本系统摒弃了传统虚拟演播室对抠像设备、跟踪器件的硬件依赖，构建了基于Unity3D引擎的纯软件分层架构。系统通过C#脚本驱动，实现了虚拟场景构建、背景合成、灯光控制及摄像机交互的全流程集成。核心功能包括虚拟大屏背景管理、双路灯光控制系统、多模式摄像机控制、场景内录制功能。适用于在线教育、网络直播、小型节目制作等场景。'),

('w029', '基于Unity的3D交互式虚拟演播厅系统', 'broadcast', '广播电视工程', '虚实共生', '["Unity", "3D交互", "虚拟演播"]', '["童叶子"]', '陈明', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/006.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/006.mp4', '03:00', '本毕设基于Unity的3D交互式虚拟演播厅系统的设计与实现，针对传统实体演播厅布景成本高、设备协同低效等痛点，以不同的节目制作需要为出发点，设计出一个基于Unity的三维交互虚拟演播室系统方案。核心模块包括：场景切换模块（红色情怀区、新闻播报区、访谈交流区）、音频及灯光调节模块、信号切换模块、抠像模块。构建出一个低成本、高灵活、沉浸式的可交互三维虚拟演播厅。'),

('w030', '基于UE5的沉浸式音视频展播场馆设计与实现', 'broadcast', '广播电视工程', '虚实共生', '["UE5", "沉浸式", "音视频展播"]', '["王楚天"]', '刘洋', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/007.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/007.mp4', '03:00', '针对传统实体展播场馆空间受限、体验形式单调、运营成本过高，以及高精度模型与多路空间音频并发调度引发性能不均、沉浸中断等难题，基于Unreal Engine 5搭建沉浸式音视频展播场馆系统。系统采用模块化架构，融合Nanite、Lumen、空间音频关键技术，以C++与蓝图协同开发。核心功能包括超写实场景构建、全动态光影渲染、三维空间音频、轻量化交互控制、智能资源调度。为文博数字化展陈、数字文旅体验、科技文创展播等提供轻量化可复用技术模式。'),

('w031', '基于知识增强语言模型的海报自动化生成系统', 'broadcast', '广播电视工程', '虚实共生', '["AI", "海报生成", "AIGC"]', '["肖金鹏"]', '周杰', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/008.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/008.mp4', '03:00', '本作品为基于知识增强语言模型的海报自动化生成系统，针对AIGC海报生成中版式控制不稳、中文文字生成质量差、本地部署门槛高等行业痛点，采用"规划-执行-合成-交互"分层架构，融合RAG+CoT推理、SDXL图像生成、YOLO主体分割与定制化文字叠加技术。可在本地4GB显存环境下，实现从自然语言输入到专业海报输出的全流程自动化，为轻量化视觉内容创作提供低成本解决方案。'),

('w032', '16讯道4K超高清EFP视频系统设计', 'broadcast', '广播电视工程', '虚实共生', '["EFP", "4K", "视频系统"]', '["高雅琦"]', '孙磊', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/009.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/009.mp4', '03:00', '本作品针对综艺活动现场制作需求，设计并实现了一套16讯道4K超高清EFP视频系统。系统采用分层模块化架构，完成全链路信号流规划、核心设备选型与系统集成，兼顾制作效率与播出安全，满足综艺活动录播与直播的全流程制作需求。系统分为信源接入层、核心调度与处理层、信号分发与录制层及终端监看辅助层，采用主备冗余架构（双切换台、双矩阵、双同步机），基于12G-SDI基带传输。'),

('w033', '基于MATLAB与软件无线电平台的OFDM无线通信系统', 'broadcast', '广播电视工程', '虚实共生', '["MATLAB", "OFDM", "无线通信"]', '["石新佳"]', '吴凯', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/010.mp4', 'https://whcm-1353140174.cos.ap-nanjing.myqcloud.com/resource/Rte/010.mp4', '03:00', '本作品是一个基于MATLAB与软件无线电平台的OFDM无线通信系统仿真项目，以广播电视工程专业的数字传输原理为核心，构建了完整的视频信号收发链路。系统采用卷积编码、QPSK调制、OFDM基带调制、RRC滤波等关键技术，通过eNodeX30B平台实现无线信号的发射与接收，同时完成载波同步、频偏补偿与信道解码，最终还原视频信号。该设计验证了OFDM技术在无线传输中的抗干扰性能，为数字广播电视系统的工程实现提供了仿真支撑。');
